const lines = $input.all().map(i => i.json);

// Flatten if nested array from XML-RPC
const flat = Array.isArray(lines[0]) ? lines[0] : lines;

// Group by account type
const groups = { AR: [], AP: [], Bank: [], Other: [] };

for (const line of flat) {
  if (!line || !line.account_id) continue;
  const acctName = Array.isArray(line.account_id) ? line.account_id[1] : String(line.account_id);
  const lower = acctName.toLowerCase();

  const entry = {
    id: line.id,
    name: line.name || '',
    account: acctName,
    partner: Array.isArray(line.partner_id) ? line.partner_id[1] : (line.partner_id || 'N/A'),
    debit: line.debit || 0,
    credit: line.credit || 0,
    residual: line.amount_residual || 0,
    date: line.date || '',
    move: Array.isArray(line.move_id) ? line.move_id[1] : (line.move_id || '')
  };

  if (lower.includes('receivable') || lower.includes('1200')) {
    groups.AR.push(entry);
  } else if (lower.includes('payable') || lower.includes('2100')) {
    groups.AP.push(entry);
  } else if (lower.includes('bank') || lower.includes('cash') || lower.includes('1010')) {
    groups.Bank.push(entry);
  } else {
    groups.Other.push(entry);
  }
}

const summary = {
  ar_count: groups.AR.length,
  ar_total: groups.AR.reduce((s, e) => s + Math.abs(e.residual), 0),
  ap_count: groups.AP.length,
  ap_total: groups.AP.reduce((s, e) => s + Math.abs(e.residual), 0),
  bank_count: groups.Bank.length,
  bank_total: groups.Bank.reduce((s, e) => s + Math.abs(e.residual), 0),
  other_count: groups.Other.length,
  total_unreconciled: flat.length,
  groups: groups
};

return [{ json: summary }];

const gptResponse = $input.first().json;
const analysis = gptResponse.choices?.[0]?.message?.content || 'No analysis generated';
const summary = $('Group by Account Type').first().json;

const today = new Date().toISOString().split('T')[0];

return [{ json: {
  task_name: `Reconciliation Review — ${today}`,
  description: `## Automated Reconciliation Check

**Run date**: ${today}
**Company**: TBWA\SMP (CID=2)

### Unreconciled Summary
- AR: ${summary.ar_count} entries (PHP ${summary.ar_total.toFixed(2)})
- AP: ${summary.ap_count} entries (PHP ${summary.ap_total.toFixed(2)})
- Bank: ${summary.bank_count} entries (PHP ${summary.bank_total.toFixed(2)})
- Total: ${summary.total_unreconciled} unreconciled lines

---

${analysis}`,
  project_id: 4,
  user_id: 17
}}];
